// Tree-shaking only works with ES module named imports and side-effect-free
// packages. This pulls in only debounce, not all of lodash:
import debounce from 'lodash-es/debounce';   // good: granular, tree-shakeable
// import _ from 'lodash';                    // bad: can drag in the whole lib

// Analyze the bundle to find the real weight before optimizing:
//   npx vite-bundle-visualizer    (Vite/Rollup)
//   npx webpack-bundle-analyzer    (webpack)
// Look for: duplicate dependencies, oversized libs, non-split routes,
