// Debounce: run fn only after `delay` ms of silence. Resets on each call.
function debounce(fn, delay) {
  let timer;
  return (...args) => {
    clearTimeout(timer);
    timer = setTimeout(() => fn(...args), delay);
  };
}

// Throttle: run fn at most once per `interval` ms, on the leading edge.
function throttle(fn, interval) {
  let last = 0;
  return (...args) => {
    const now = Date.now();
    if (now - last >= interval) {
      last = now;
      fn(...args);
    }
  };
}

// Search fires after the user stops typing for 300ms (one request, not one per key).
searchInput.addEventListener('input', debounce(e => fetchResults(e.target.value), 300));

// Scroll handler runs at most ~10x/sec instead of on every scroll event.
window.addEventListener('scroll', throttle(updateScrollProgress, 100), { passive: true });

