function debounce(fn, delay) {
  let timer = null;
  let lastArgs = null;
  let lastThis = null;
  return function (...args) {
    lastArgs = args;
    lastThis = this;
    clearTimeout(timer);              // each call resets the countdown
    timer = setTimeout(() => {
      fn.apply(lastThis, lastArgs);   // fire once, after the quiet period
      timer = null;
    }, delay);
  };
}

function throttle(fn, interval) {
  let last = 0;
  let trailingTimer = null;
  let lastArgs = null;
  let lastThis = null;
  return function (...args) {
    const now = Date.now();
    lastArgs = args;
    lastThis = this;
    const remaining = interval - (now - last);
    if (remaining <= 0) {
      // Leading edge: enough time has passed, run immediately.
      if (trailingTimer) { clearTimeout(trailingTimer); trailingTimer = null; }
      last = now;
      fn.apply(lastThis, lastArgs);
    } else if (!trailingTimer) {
      // Schedule a single trailing call so the last event is not lost.
      trailingTimer = setTimeout(() => {
        last = Date.now();
        trailingTimer = null;
        fn.apply(lastThis, lastArgs);
      }, remaining);
    }
  };
}

// Search input: debounce so one request fires after the user stops typing.
const onSearch = debounce(q => fetchResults(q), 300);
// Scroll handler: throttle so progress updates at a steady max rate.
const onScroll = throttle(() => updateProgressBar(), 100);

// React component; the same structure works as plain HTML.
function ResponsiveImage({
  name,        // base path without extension, e.g. '/img/hero'
  widths,      // e.g. [480, 960, 1440]
  sizes,       // e.g. '(max-width: 600px) 100vw, 960px'
  width,       // intrinsic width for aspect ratio (CLS reservation)
  height,      // intrinsic height
  alt,         // required for accessibility
  priority = false, // true for the LCP image
}) {
  const srcset = (ext) =>
    widths.map((w) => `${name}-${w}.${ext} ${w}w`).join(', ');

  return (
    <picture>
      <source type="image/avif" srcSet={srcset('avif')} sizes={sizes} />
      <source type="image/webp" srcSet={srcset('webp')} sizes={sizes} />
      <img
        src={`${name}-${widths[widths.length - 1]}.jpg`}
        srcSet={srcset('jpg')}
        sizes={sizes}
        width={width}
        height={height}          /* reserves space -> no CLS */
        alt={alt}                /* accessibility */
        loading={priority ? 'eager' : 'lazy'}
        fetchpriority={priority ? 'high' : 'low'}
        decoding="async"          /* keep decode off the critical path */
      />
    </picture>
  );
}

// Usage:
// LCP hero -> priority so it loads early, never lazy.
<ResponsiveImage name="/img/hero" widths={[480, 960, 1440]}
  sizes="(max-width:600px) 100vw, 960px" width={1440} height={810}
  alt="Product hero" priority />

// Below-the-fold thumbnail -> lazy, low priority.
<ResponsiveImage name="/img/thumb" widths={[160, 320]}
  sizes="160px" width={320} height={180} alt="Thumbnail" />
